// HasTicketSeats applies the HasEdge predicate on the "ticketSeats" edge.
func HasTicketSeats() predicate.Ticket {
	return predicate.Ticket(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, TicketSeatsTable, TicketSeatsColumn),
		)
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.TicketSeat
		step.Edge.Schema = schemaConfig.TicketSeat
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTicketSeatsWith applies the HasEdge predicate on the "ticketSeats" edge with a given conditions (other predicates).
func HasTicketSeatsWith(preds ...predicate.TicketSeat) predicate.Ticket {
	return predicate.Ticket(func(s *sql.Selector) {
		step := newTicketSeatsStep()
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.TicketSeat
		step.Edge.Schema = schemaConfig.TicketSeat
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Ticket) predicate.Ticket {
	return predicate.Ticket(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Ticket) predicate.Ticket {
	return predicate.Ticket(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Ticket) predicate.Ticket {
	return predicate.Ticket(sql.NotPredicates(p))
}
